VALUES
  ('judicial-57112235-moex-00227', 'judicial-57112235', 'judicial-57112235-moex-113-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關戒護技術與原則，下列敘述何者正確？', '["依國內外之監獄分類管理施行原則，僅區分為高度戒護及低度戒護兩種戒護類型", "違禁品乃矯正機關發生各項騷擾與暴行之泉源，須有一套完善之管理計畫", "勤務崗位之分析係著重於像戒護外醫、監外作業等高脫逃風險之勤務，不包括監內一般勤務分析", "武器使用易釀成嚴重傷亡，監獄為人口密集處所，已廢除武器之使用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "bf4b5d100335", "answer_pdf_sha1": "c80fae1e3f59", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00228', 'judicial-57112235', 'judicial-57112235-moex-113-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '據學者Bartollas之看法，犯罪矯正主流哲學有三種模式，不包括下列何者？', '["矯治模式", "隔離模式", "正義模式", "懲罰模式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "bf4b5d100335", "answer_pdf_sha1": "c80fae1e3f59", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00229', 'judicial-57112235', 'judicial-57112235-moex-113-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '關於高齡受刑人監獄生活適應之問題，下列敘述何者正確？', '["高齡受刑人監獄生活適應型態研究指出：其違規次數與年輕受刑人並無差異", "相較於年輕受刑人，高齡受刑人比較會設定人生目標及維持高等社會活動之意願", "高齡受刑人沮喪、沉重、空虛等負向情緒是常有的心理反應", "高齡受刑人對矯正部門之依賴較低，重返自由社會之恐懼感亦不高"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "bf4b5d100335", "answer_pdf_sha1": "c80fae1e3f59", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00230', 'judicial-57112235', 'judicial-57112235-moex-113-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '關於對收容人違規處罰程序及方式，下列敘述何者錯誤？', '["各國處罰程序大致規定經過報告、聽證、紀錄三種過程", "非依法令之規定不得加以懲處，同一事件不得重複懲處", "在給予適當解辯之機會前，不得加以懲處", "懲罰之方式包括權益之剝奪及體罰等項目"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "bf4b5d100335", "answer_pdf_sha1": "c80fae1e3f59", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00231', 'judicial-57112235', 'judicial-57112235-moex-113-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '根據學者JohnIrwin對適應監獄生活型態為「打混型」（DoingTime）的受刑人之看法，下列敘述 何者錯誤？', '["認為監禁對個人生涯而言只是一段小插曲", "致力於尋求最舒適的服刑環境，以避免監禁的痛苦", "從事必要的「工作」以儘速的離開監獄", "大都為自小即在少年矯正機構鬼混之常客"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "bf4b5d100335", "answer_pdf_sha1": "c80fae1e3f59", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00232', 'judicial-57112235', 'judicial-57112235-moex-113-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', 'O’Leary與Duffee於1971年提出犯罪矯正政策模式，下列對各模式的敘述，何者錯誤？', '["鎮壓模式的哲學是「維持門面、隨波逐流」", "改善模式下的犯罪矯正職員對於人犯至為嚴厲但卻相當地公平", "矯治模式下，戒護人員被期待如專業人員一般積極地參與人性改造工作", "社會復歸模式下，各項犯罪矯正方案由受刑人與職員共同研商發展而成"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "bf4b5d100335", "answer_pdf_sha1": "c80fae1e3f59", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00233', 'judicial-57112235', 'judicial-57112235-moex-113-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '關於戒護收容人外醫勤務之應注意事項，下列敘述何者錯誤？', '["戒護收容人在外就醫，應依法施用戒具，並隨時檢查", "收容人住院時，遇其親友探視僅需回報勤務中心，不需登記與檢查", "收容人病危時，應從速向主管長官報告", "戒護收容人在外就醫時，不能任收容人脫離戒護視線，無論其如廁、洗浴、醫療，均應同行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "bf4b5d100335", "answer_pdf_sha1": "c80fae1e3f59", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00234', 'judicial-57112235', 'judicial-57112235-moex-113-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '監獄附設補校，提供受刑人接受高中職或大學同等學歷課程的機會，促使受刑人學習。請問前述 作為係屬何種教育？', '["學校教育", "職業教育", "社會教育", "品德教育"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "bf4b5d100335", "answer_pdf_sha1": "c80fae1e3f59", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00235', 'judicial-57112235', 'judicial-57112235-moex-113-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '民眾王先生在「矯正機關自營商城」的網頁上選購巧克力及滴雞精，前述產品均為受刑人生產製 作，請問這是屬何種作業制度下生產的產品？', '["委託業制", "官用業制", "公共事業制", "國營業制 20620"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "bf4b5d100335", "answer_pdf_sha1": "c80fae1e3f59", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00236', 'judicial-57112235', 'judicial-57112235-moex-113-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '關於監獄暴行之類型、原因與預防方式，下列敘述何者正確？', '["監獄暴行類型專指受刑人對受刑人或管理人員暴行，並不包括管理人員對受刑人之暴行", "工具性監獄暴行係指為達成某種特定目的而以一種較合乎理性之方式進行暴行而言", "暴行發生的原因與受刑人個人因素及情境因素有關，而與文化、地理環境或建築結構因素無關", "強化酬賞及康樂活動安排減輕監禁痛楚，並無法減少監獄暴行之發生"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "bf4b5d100335", "answer_pdf_sha1": "c80fae1e3f59", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
